$utilisateurs = @(
    [PSCustomObject]@{ Nom='Alice';   Departement='IT'; Actif=$true  },
    [PSCustomObject]@{ Nom='Bob';     Departement='IT'; Actif=$false },
    [PSCustomObject]@{ Nom='Charlie'; Departement='RH'; Actif=$true  }
)

$actifs = $utilisateurs | Where-Object Actif -eq $true
$actifs | ForEach-Object { Write-Host "$($_.Nom),$($_.Departement),$($_.Actif)" }
